-- Marketing claim codes (1,000 pre-seeded). A code is redeemed by a signed-in
-- wallet via /api/claim; "eligible" for the free mint = claimed AND the claimer's
-- 0.0.x has >=1 on-chain dApp tx, resolved through users.account_id so BOTH wallet
-- types (HashPack/Ed25519 long-zero + MetaMask/ECDSA alias) track correctly.
-- The on-chain NFT mint is a later step; this records claim + eligibility only.
create table if not exists public.claim_codes (
  code               text primary key check (length(code) between 5 and 12),
  claimed            boolean not null default false,
  claimed_by_address text,
  claimed_by_account_id text,
  claimed_at         timestamptz
);
create index if not exists claim_codes_claimed_by_idx on public.claim_codes (claimed_by_address);
alter table public.claim_codes enable row level security;  -- service-role only

-- One claim per wallet.
create unique index if not exists claim_codes_one_per_wallet
  on public.claim_codes (claimed_by_address) where claimed_by_address is not null;

-- Aggregate counters for the operator: total / claimed / eligible(claimed + >=1 tx).
-- Eligibility resolves via coalesce(users.account_id, claimed_by_account_id) — the
-- same fresh source the referral system uses, so late-resolved accounts still count.
create or replace function public.claim_stats()
returns table(total int, claimed int, eligible int)
language sql stable security definer set search_path = public as $$
  with tx_accts as (
    select distinct longzero_to_account(payload->>'from_raw') as acct
    from activity_log
    where payload->>'result' = 'SUCCESS' and longzero_to_account(payload->>'from_raw') is not null
  ),
  resolved as (
    select c.claimed,
           coalesce(u.account_id, c.claimed_by_account_id) as acct
    from claim_codes c
    left join users u on u.address = c.claimed_by_address
  )
  select count(*)::int,
         count(*) filter (where claimed)::int,
         count(*) filter (
           where claimed and acct is not null
             and exists (select 1 from tx_accts t where t.acct = resolved.acct)
         )::int
  from resolved;
$$;
grant execute on function public.claim_stats() to service_role;

